  // Codicon 24x24 viewBox exceptions (all others are 16x16)
  const codicon24 = new Set(['settings-gear']);

  const resolved = $derived.by(() => {
    if (source === 'lucide') {
      return { data: lucideIcons[name] ?? lucideIcons['x'], source: 'lucide' as const };
    }
    if (source === 'codicon') {
      return { data: codiconIcons[name] ?? lucideIcons['x'], source: 'codicon' as const };
    }
    // Auto-detect: lucide first (larger set)
    if (name in lucideIcons) return { data: lucideIcons[name], source: 'lucide' as const };
    if (name in codiconIcons) return { data: codiconIcons[name], source: 'codicon' as const };
    return { data: lucideIcons['x'], source: 'lucide' as const };
  });

  const isCodicon = $derived(resolved.source === 'codicon');
  const viewBox = $derived(isCodicon ? (codicon24.has(name) ? '0 0 24 24' : '0 0 16 16') : '0 0 24 24');

  const getIconPaths = $derived.by(() => {
    const iconData = resolved.data;
    if (Array.isArray(iconData)) return iconData;
    return [iconData as string];
  });
