    <title>{title}</title>
  {/if}
  {#each getIconPaths as pathData, index (index)}
    <path
      d={pathData}
      stroke={isCodicon ? 'none' : (index === 0 && pathData.includes('M0 0h24v24H0z') ? 'none' : undefined)}
